def mse_loss(predictions, targets):
    total = sum((p - t) ** 2 for p, t in zip(predictions, targets))
    return total / len(predictions)

predictions = [0.5, 0.0]
targets     = [1.0, 0.0]
print(f"Loss: {mse_loss(predictions, targets):.4f}")

